  "get_pipeline_context": {
    "description": "Retrieves metadata and logs for a specific pipeline execution to identify affected components and the previous stable version.",
    "parameters": {
      "type": "object",
      "properties": {
        "pipeline_id": {
          "type": "string",
          "description": "The unique identifier for the pipeline run (e.g., 'pipe-z-8821')."
        }
      },
      "required": [
        "pipeline_id"
      ]
    },
    "example_output": {
      "module_name": "ACCTCALC",
      "load_library": "PROD.LOADLIB",
      "db2_plan": "ACCTPLAN",
      "previous_stable_version": "v2.1.0",
      "failed_version": "v2.2.0",
      "temp_artifacts": [
        "WORK.BUILD.TEMP1",
        "WORK.BIND.LOG"
      ]
    }
  },
  "manage_zos_load_module": {
    "description": "Performs operations on Z/OS load modules within a Partitioned Data Set (PDS).",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "restore",
            "list_versions",
            "backup"
          ],
          "description": "The operation to perform."
        },
        "dataset_name": {
          "type": "string",
          "description": "The PDS containing the load module."
        },
        "module_name": {
          "type": "string",
          "description": "The name of the load module/member."
        },
        "target_version": {
          "type": "string",
          "description": "The version tag or timestamp to restore to."
        }
      },
      "required": [
        "action",
        "dataset_name",
        "module_name"
      ]
    },
    "example_output": {
      "status": "success",
      "restored_member": "ACCTCALC",
      "timestamp": "2023-10-27 10:00:00"
    }
  },
  "manage_db2_plan": {
    "description": "Manages DB2 plan bindings and package synchronization.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "bind",
            "check_status"
          ],
          "description": "The DB2 action to perform."
        },
        "plan_name": {
          "type": "string",
          "description": "The name of the DB2 plan."
        },
        "version": {
          "type": "string",
          "description": "The target version/collection ID to bind to the plan."
        }
      },
      "required": [
        "action",
        "plan_name"
      ]
    },
    "example_output": {
      "status": "success",
      "current_bind_version": "v2.1.0"
    }
  },
  "refresh_cics_resource": {
    "description": "Performs a NEWCOPY or PHASEIN on a program within a specified CICS region to update the in-memory executable.",
    "parameters": {
      "type": "object",
      "properties": {
        "region_id": {
          "type": "string",
          "description": "The identifier for the CICS region (e.g., 'FINREG01')."
        },
        "program_name": {
          "type": "string",
          "description": "The name of the program to refresh."
        }
      },
      "required": [
        "region_id",
        "program_name"
      ]
    },
    "example_output": {
      "status": "success",
      "newcopy_count": 1
    }
  },
  "cleanup_zos_artifacts": {
    "description": "Deletes temporary datasets or artifacts generated during a failed deployment.",
    "parameters": {
      "type": "object",
      "properties": {
        "artifact_list": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "A list of dataset names or file paths to delete."
        }
      },
      "required": [
        "artifact_list"
      ]
    },
    "example_output": {
      "deleted": [
        "WORK.BUILD.TEMP1"
      ],
      "failed": []
    }
  },
  "verify_system_consistency": {
    "description": "Checks if the load module, DB2 plan, and CICS region are all running the same version.",
    "parameters": {
      "type": "object",
      "properties": {
        "module_name": {
          "type": "string"
        },
        "db2_plan": {
          "type": "string"
        },
        "cics_region": {
          "type": "string"
        }
      },
      "required": [
        "module_name",
        "db2_plan",
        "cics_region"
      ]
    },
    "example_output": {
      "consistent": true,
      "details": {
        "load_module_version": "v2.1.0",
        "db2_version": "v2.1.0",
        "cics_version": "v2.1.0"
